BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?childName ?childType ?superClassName WHERE {
  ?elem vocab:NamedElement_name "Maintenance%20Alignment%20duration%20trade%20study" .
  {
    ?elem vocab:Element_ownedElement ?child .
    ?child vocab:NamedElement_name ?childName .
    ?child rdf:type ?childType .
  }
  UNION
  {
    ?elem vocab:Class_superClass ?super .
    ?super vocab:NamedElement_name ?superClassName .
  }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?childType WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "duration%20trade%20study"))
  ?elem vocab:Element_ownedElement ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
  OPTIONAL { ?child rdf:type ?childType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?generalName ?generalType WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "duration%20trade%20study"))
  ?elem vocab:Classifier_generalization ?gen .
  ?gen vocab:Generalization_general ?general .
  OPTIONAL { ?general vocab:NamedElement_name ?generalName . }
  OPTIONAL { ?general rdf:type ?generalType . }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?childName ?childType WHERE {
  ?pkg vocab:NamedElement_name ?pname .
  FILTER(CONTAINS(STR(?pname), "Maintenance%20Alignment%20Trade%20Study%20Analysis"))
  ?pkg rdf:type vocab:package .
  ?pkg vocab:Element_ownedElement ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
  OPTIONAL { ?child rdf:type ?childType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childType WHERE {
  VALUES ?pkgURI { 
    <TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::10%20Analysis::Trade%20studies::Maintenance%20Alignment%20Trade%20Study%20Analysis::Alternatives>
  }
  ?pkgURI vocab:Element_ownedElement ?child .
  OPTIONAL { ?child rdf:type ?childType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?childType WHERE {
  ?child vocab:Element_owner ?pkg .
  FILTER(CONTAINS(STR(?pkg), "Maintenance%20Alignment%20Trade%20Study") && CONTAINS(STR(?pkg), "Alternatives"))
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
  OPTIONAL { ?child rdf:type ?childType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childName ?childType WHERE {
  ?child vocab:Element_owner ?pkg .
  FILTER(CONTAINS(STR(?pkg), "Maintenance%20Alignment%20Trade%20Study") && CONTAINS(STR(?pkg), "Analysis%20results"))
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
  OPTIONAL { ?child rdf:type ?childType . }
  FILTER(!BOUND(?childType) || ?childType != vocab:slot)
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?attrName ?attrType ?attrTypeName WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "duration%20trade%20study"))
  ?elem rdf:type vocab:block .
  ?elem vocab:Class_ownedAttribute__from_Class ?attr .
  OPTIONAL { ?attr vocab:NamedElement_name ?attrName . }
  OPTIONAL { 
    ?attr vocab:TypedElement_type ?atype .
    ?atype vocab:NamedElement_name ?attrTypeName .
  }
  OPTIONAL { ?attr rdf:type ?attrType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?commentBody ?activityName ?opName WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "duration%20trade%20study"))
  ?elem rdf:type vocab:block .
  {
    ?elem vocab:Element_ownedElement ?comment .
    ?comment rdf:type vocab:comment .
    ?comment vocab:Comment_body ?commentBody .
  }
  UNION
  {
    ?elem vocab:BehavioredClassifier_ownedBehavior ?activity .
    ?activity vocab:NamedElement_name ?activityName .
  }
  UNION
  {
    ?elem vocab:Class_ownedOperation ?op .
    ?op vocab:NamedElement_name ?opName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?node ?nodeType ?nodeName WHERE {
  ?activity a vocab:activity .
  FILTER(CONTAINS(STR(?activity), "evaluateAlternativeDuration"))
  ?activity vocab:Activity_node ?node .
  OPTIONAL { ?node vocab:NamedElement_name ?nodeName . }
  OPTIONAL { ?node rdf:type ?nodeType . }
}
LIMIT 25
